// Scans public/products/ and generates src/data/productImages.ts, mapping each
// SKU to its photo paths. Convention:
//   public/products/<SKU>.jpg        -> primary image
//   public/products/<SKU>-1.jpg, ... -> additional gallery shots (in order)
//
// Runs automatically before `npm run dev` and `npm run build` (see package.json
// pre-hooks). The generated file is committed so deploys work even if the host
// runs `vite build` directly. Drop files in the folder and rebuild — never edit
// products.ts to wire an image.
import { readFileSync, writeFileSync, readdirSync, existsSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const root = join(dirname(fileURLToPath(import.meta.url)), "..");
const productsFile = join(root, "src/data/products.ts");
const imagesDir = join(root, "public/products");
const outFile = join(root, "src/data/productImages.ts");

const IMAGE_EXT = /\.(jpe?g|png|webp)$/i;
const escapeRe = (s) => s.replace(/[-/\\^$*+?.()|[\]{}]/g, "\\$&");

// 1. Authoritative SKU list, read from products.ts as text (not imported, so no
//    dependency cycle with the file we generate).
const productsSrc = readFileSync(productsFile, "utf8");
const skus = [...new Set([...productsSrc.matchAll(/sku:\s*"([^"]+)"/g)].map((m) => m[1]))];
// Longest first so "A-B-100-1" matches SKU "A-B-100" before any shorter SKU.
const skusByLength = [...skus].sort((a, b) => b.length - a.length);

// 2. Scan the image folder.
const files = existsSync(imagesDir)
  ? readdirSync(imagesDir).filter((f) => IMAGE_EXT.test(f))
  : [];

// 3. Match each file to a SKU. <SKU>.<ext> is primary (order 0); <SKU>-<n>.<ext>
//    is extra shot n.
const grouped = {};
const unmatched = [];
for (const file of files) {
  const base = file.replace(IMAGE_EXT, "");
  const sku = skusByLength.find(
    (s) => base === s || new RegExp(`^${escapeRe(s)}-\\d+$`).test(base)
  );
  if (!sku) {
    unmatched.push(file);
    continue;
  }
  const order = base === sku ? 0 : Number(base.slice(sku.length + 1));
  (grouped[sku] ??= []).push({ order, path: `/products/${file}` });
}

// 4. Sort each SKU's shots (primary, then -1, -2 …) and flatten to paths.
const result = {};
for (const sku of Object.keys(grouped).sort()) {
  result[sku] = grouped[sku].sort((a, b) => a.order - b.order).map((x) => x.path);
}

if (unmatched.length) {
  console.warn(
    `[product-images] ${unmatched.length} file(s) matched no SKU (ignored): ${unmatched.join(", ")}`
  );
}

// 5. Emit the generated module.
const banner =
  "// AUTO-GENERATED by scripts/generate-product-images.mjs — do not edit by hand.\n" +
  "// Maps each SKU to its photos in public/products/ (<SKU>.jpg primary, <SKU>-N.jpg extras).\n" +
  "// Regenerated automatically on `npm run dev` and `npm run build`.\n";
const body = `export const productImages: Record<string, string[]> = ${JSON.stringify(result, null, 2)};\n`;
writeFileSync(outFile, `${banner}\n${body}`);

console.log(
  `[product-images] wired ${Object.keys(result).length} product(s) from ${files.length} file(s).`
);
